const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const basePremiumForItems = (items: any[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const quotePremium = (items: any[]): number => {
  const policyBase = basePremiumForItems(items);
  const withFirstInsurance = policyBase * (1 + FIRST_INSURANCE_SURCHARGE_RATE);
  return Math.ceil(withFirstInsurance) + PROCESSING_FEE;
};

export const runScenario = (scenario: any): unknown => {
  const results = scenario.steps.map((step: any) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

